#include <iostream>\n#include <cstdint>\n#include <vector>\n\nclass Graph {\n public:\n  Graph(size_t n, std::vector<std::pair<size_t, size_t>> edges) {\n    table_.resize(n + 1);\n    visited_.resize(n + 1);\n    Build(edges);\n  }\n\n  std::vector<std::vector<size_t>> GetComponents() {\n    for (size_t i = 1; i < visited_.size(); i++) {\n      if (!visited_[i]) {\n        std::vector<size_t> nodes;\n        nodes.push_back(i);\n        Dfs(i, nodes);\n        comps_.push_back(nodes);\n      }\n    }\n    return comps_;\n  }\n\n private:\n  void Build(const std::vector<std::pair<size_t, size_t>>& edges) {\n    for (const std::pair<size_t, size_t>& pair : edges) {\n      auto i = pair.first;\n      auto j = pair.second;\n      table_[i].push_back(j);\n      table_[j].push_back(i);\n    }\n  }\n\n  void Dfs(size_t start, std::vector<size_t>& comp) {\n    visited_[start] = true;\n    const std::vector<size_t>& children = table_[start];\n    for (auto i : children) {\n      if (!visited_[i]) {\n        comp.push_back(i);\n        Dfs(i, comp);\n      }\n    }\n  }\n\n  std::vector<std::vector<size_t>> comps_;\n  std::vector<std::vector<size_t>> table_;\n  std::vector<bool> visited_;\n};\n\nint main() {\n  size_t n = 0;\n  size_t m = 0;\n  std::cin >> n >> m;\n  std::vector<std::pair<size_t, size_t>> edges(m);\n  for (size_t it = 0; it < m; it++) {\n    size_t i = 0;\n    size_t j = 0;\n    std::cin >> i >> j;\n    edges[it] = {i, j};\n  }\n\n  Graph graph(n, edges);\n  auto comps = graph.GetComponents();\n\n  std::cout << comps.size() << std::endl;\n  for (const std::vector<size_t>& comp : comps) {\n    std::cout << comp.size() << std::endl;\n    for (auto i : comp) {\n      std::cout << i << ' ';\n    }\n    std::cout << std::endl;\n  }\n  return 0;\n}